const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const message_id = $('Normalizar Datos').item.json.message_id;

// IMPORTANTE: Pega aquí tu clave secreta de Supabase (service_role)
const SUPABASE_KEY = "PEGA_TU_CLAVE_SERVICE_ROLE_AQUI";

const URL = `https://rcqkmaxkuxllcyjzqbvn.supabase.co/storage/v1/object/documentos_operacionales/kommo_${message_id}.jpg`;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: URL,
    headers: {
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'image/jpeg',
      'x-upsert': 'true'
    },
    body: buffer,
    data: buffer,
    encoding: null
  });
  return { json: { success: true, response } };
} catch (error) {
  // DEVOLVEMOS EL ERROR COMO JSON PARA PODER LEERLO EN PANTALLA
  return { json: { error_detectado: true, mensaje: error.message, detalles_supabase: error.response?.data } };
}
